{"code": "# Read the README contents data
readme_content = locals()['var_functions.query_db:26']
import json
import os

if isinstance(readme_content, str):
    file_path = readme_content
    if os.path.exists(file_path):
        with open(file_path, 'r') as f:
            readme_data = json.load(f)
    else:
        path = '/tmp/data_analyst_agent/' + file_path
        with open(path, 'r') as f:
            readme_data = json.load(f)
else:
    readme_data = readme_content

# Get the list of non-Python repositories
languages_data = locals()['var_functions.query_db:14']
if isinstance(languages_data, str):
    file_path = languages_data
    if os.path.exists(file_path):
        with open(file_path, 'r') as f:
            languages_data = json.load(f)
    else:
        path = '/tmp/data_analyst_agent/' + file_path
        with open(path, 'r') as f:
            languages_data = json.load(f)

# Filter non-Python repositories
non_python_repos = set()
for item in languages_data:
    if 'python' not in item['language_description'].lower():
        non_python_repos.add(item['repo_name'])

# Check which repositories have both README and are non-Python
readme_repos = set(item['sample_repo_name'] for item in readme_data)
non_python_with_readme = non_python_repos.intersection(readme_repos)

print("__RESULT__:")
print(json.dumps({
    "total_non_python": len(non_python_repos),
    "total_readme_repos": len(readme_repos),
    "non_python_with_readme": len(non_python_with_readme)
}))"}

